sysauto_script.script:
var targetTables = [
    'sn_customerservice_case',
    'sys_email',
    'sys_attachment',
    'change_task',
    'u_event_task',
    'change_request',
    'problem',
    'sys_data_source'
];

var totalRecordCount = 0;
var totalAttachmentCount = 0;

// Store unique records with attachments per table
var recordsWithAttachments = {};

for (var t = 0; t < targetTables.length; t++) {
    var tableName = targetTables[t];
    recordsWithAttachments[tableName] = [];

    var gr = new GlideRecord(tableName);

    if (!gr.isValidField('sys_created_on')) {
        gs.print('Skipping table (no sys_created_on): ' + tableName);
        continue;
    }

    // Records older than 5 years
    gr.addQuery('sys_created_on', '<', gs.yearsAgo(5));
    //gr.setLimit(100);
    gr.query();

    while (gr.next()) {
        totalRecordCount++;
        var hasAttachment = false;
        var attGR = new GlideRecord('sys_attachment');
        attGR.addQuery('table_name', tableName);
        attGR.addQuery('table_sys_id', gr.sys_id);
        attGR.query();
        while (attGR.next()) {
            hasAttachment = true;
            totalAttachmentCount++;
            gs.print(
                'Found attachment: ' + attGR.file_name +
                ' | Table: ' + tableName +
                ' | Record Sys ID: ' + gr.sys_id
            );
            // Delete attachment
            new GlideSysAttachment().deleteAttachment(attGR.sys_id);
        }
        if (hasAttachment) {
            recordsWithAttachments[tableName].push(gr.sys_id.toString());
        }
    }
}

gs.print('Total Records Processed: ' + totalRecordCount);
gs.print('Total Attachments Deleted: ' + totalAttachmentCount);

for (var tbl in recordsWithAttachments) {
    gs.print(
        'Table: ' + tbl +
        ' | Records with attachments: ' + recordsWithAttachments[tbl].length
    );

    if (recordsWithAttachments[tbl].length > 0) {
        gs.print(
            'Record Sys IDs: ' + recordsWithAttachments[tbl].join(', ')
        );
    }
}
